CREATE OR REPLACE FUNCTION fpa_tel_get_memno_by_appno (as_appno char) RETURNS SC_MEM_M_MEMBERSHIP_REGISTERED.MEMBERSHIP_NO%TYPE AS $body$
DECLARE

  ls_memno sc_mem_m_membership_registered.membership_no%type;

BEGIN
  select membership_no into STRICT ls_memno
  from sc_mem_m_membership_registered
  where application_form_no = as_appno
;
  if coalesce(ls_memno::text, '') = '' then ls_memno := ' ';end if;
  return ls_memno;

end;
$body$
